using Dapper; using Valora.Application.Contracts; using Valora.Application.DTOs; using Valora.Infrastructure.Database;
namespace Valora.Infrastructure.Repositories;
public sealed class OrganizationRepository(IDbConnectionFactory f):IOrganizationRepository{ public async Task<dynamic?> GetAsync(Guid id){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT id,name,public_name,email,phone,document,status,plan_id FROM valora.organizations WHERE id=@id AND is_deleted=false",new{id});} public async Task<Guid> CreateAsync(string name,string email,string slug,string planId){using var c=f.Create(); return await c.ExecuteScalarAsync<Guid>("INSERT INTO valora.organizations(name,public_name,email,slug,plan_id) VALUES (@name,@name,@email,@slug,@planId) RETURNING id",new{name,email,slug,planId});} public async Task UpdateCurrentAsync(Guid id,UpdateOrganizationRequest r){using var c=f.Create(); await c.ExecuteAsync("UPDATE valora.organizations SET public_name=COALESCE(@PublicName,public_name), phone=COALESCE(@Phone,phone), document=COALESCE(@Document,document), updated_at=now() WHERE id=@id",new{r.PublicName,r.Phone,r.Document,id});} public async Task<int> CountManagersAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valora.users WHERE organization_id=@organizationId AND is_deleted=false AND status='active'",new{organizationId});}}
public sealed class UserRepository(IDbConnectionFactory f):IUserRepository{ public async Task<dynamic?> GetByEmailAsync(string email){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT * FROM valora.users WHERE lower(email)=lower(@email) AND is_deleted=false",new{email});} public async Task<dynamic?> GetAsync(Guid id){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT id,organization_id,name,email,role,status FROM valora.users WHERE id=@id",new{id});} public async Task<Guid> CreateAsync(Guid organizationId,string name,string email,string passwordHash,string role){using var c=f.Create(); return await c.ExecuteScalarAsync<Guid>("INSERT INTO valora.users(organization_id,name,email,password_hash,role) VALUES (@organizationId,@name,@email,@passwordHash,@role) RETURNING id",new{organizationId,name,email,passwordHash,role});} public async Task TouchLoginAsync(Guid id){using var c=f.Create(); await c.ExecuteAsync("UPDATE valora.users SET last_login_at=now() WHERE id=@id",new{id});}}
public sealed class PlanRepository(IDbConnectionFactory f):IPlanRepository{ public async Task<IReadOnlyList<PlanDto>> GetPublicPlansAsync(){using var c=f.Create(); var plans=(await c.QueryAsync<dynamic>("SELECT * FROM billing.plans WHERE visible_on_public_pricing=true AND status='active' ORDER BY display_order")).ToList(); var result=new List<PlanDto>(); foreach(var p in plans) result.Add(await Hydrate((string)p.id,p)); return result;} public async Task<PlanDto?> GetByIdAsync(string id){using var c=f.Create(); var p=await c.QuerySingleOrDefaultAsync<dynamic>("SELECT * FROM billing.plans WHERE id=@id",new{id}); return p is null?null:await Hydrate(id,p);} async Task<PlanDto> Hydrate(string id,dynamic p){using var c=f.Create(); var limits=(await c.QueryAsync<(string limit_key,int limit_value)>("SELECT limit_key,limit_value FROM billing.plan_limits WHERE plan_id=@id",new{id})).ToDictionary(x=>x.limit_key,x=>x.limit_value); var caps=(await c.QueryAsync<(string capability_key,string capability_level)>("SELECT capability_key,capability_level FROM billing.plan_capabilities WHERE plan_id=@id",new{id})).ToDictionary(x=>x.capability_key,x=>x.capability_level); return new(id,(string)p.name,(string?)p.badge,(string)p.price_label,(string?)p.price_complement,(int)p.display_order,limits,caps);} public async Task<string?> GetCurrentPlanIdAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<string?>("SELECT plan_id FROM billing.subscriptions WHERE organization_id=@organizationId AND status='active' ORDER BY created_at DESC LIMIT 1",new{organizationId});} public async Task CreateSubscriptionAsync(Guid organizationId,string planId){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO billing.subscriptions(organization_id,plan_id) VALUES (@organizationId,@planId)",new{organizationId,planId});}}
public sealed class SurveyRepository(IDbConnectionFactory f):ISurveyRepository,IResponseRepository{
 public async Task<dynamic?> GetPublicByTokenAsync(string token){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT s.id,s.organization_id,s.form_id,s.title,s.description,s.status,s.expires_at,o.public_name AS organization_name FROM valora.surveys s JOIN valora.organizations o ON o.id=s.organization_id WHERE s.token_hash=@token AND s.is_deleted=false AND s.status IN ('active','published','open') AND (s.expires_at IS NULL OR s.expires_at>now())",new{token});}
 public async Task<Guid> SaveResponseAsync(Guid surveyId,SubmitResponseRequest r){using var c=f.Create(); c.Open(); using var tx=c.BeginTransaction(); try{ var s=await c.QuerySingleAsync<dynamic>("SELECT organization_id,form_id FROM valora.surveys WHERE id=@surveyId AND is_deleted=false",new{surveyId},tx); var resultToken=$"result_{Guid.NewGuid():N}"; var id=await c.ExecuteScalarAsync<Guid>("INSERT INTO valora.responses(organization_id,survey_id,form_id,participant_name,participant_email,result_token_hash,completed_at) VALUES (@organization_id,@surveyId,@form_id,@ParticipantName,@ParticipantEmail,@resultToken,now()) RETURNING id",new{s.organization_id,s.form_id,surveyId,r.ParticipantName,r.ParticipantEmail,resultToken},tx); var questions=(await c.QueryAsync<dynamic>("SELECT id,dimension_id,display_order FROM valora.questions WHERE form_id=@form_id AND is_deleted=false ORDER BY display_order",new{s.form_id},tx)).ToList(); decimal total=0; var dimensionTotals=new Dictionary<Guid,decimal>(); foreach(var q in questions){ var key=((Guid)q.id).ToString(); object? raw=null; if(r.Answers is not null && (!r.Answers.TryGetValue(key,out raw))) r.Answers.TryGetValue($"q{(int)q.display_order}",out raw); var score=raw is null?0:Math.Clamp(Convert.ToDecimal(raw),0,5); total+=score; var dim=(Guid)q.dimension_id; dimensionTotals[dim]=dimensionTotals.GetValueOrDefault(dim)+score; await c.ExecuteAsync("INSERT INTO valora.response_answers(response_id,question_id,answer_json,answer_text,score,max_score) VALUES (@id,@questionId,jsonb_build_object('value',@raw),@text,@score,5)",new{id,questionId=(Guid)q.id,raw=raw?.ToString(),text=raw?.ToString(),score},tx); } var label=total switch { >=25 and <=55=>"Crítico", >=56 and <=85=>"Em estruturação", >=86 and <=110=>"Estruturada", >=111=>"Alta maturidade", _=>"Crítico"}; await c.ExecuteAsync("INSERT INTO valora.result_scores(organization_id,response_id,total_score,max_score,percentage,maturity_label,strategic_truth,devolutiva_json) VALUES (@organizationId,@id,@total,125,@percentage,@label,@truth,jsonb_build_object('source','api-postgresql'))",new{organizationId=(Guid)s.organization_id,id,total,percentage=Math.Round(total/125*100,2),label,truth="Resultado calculado pela API ASP.NET Core/PostgreSQL."},tx); foreach(var dt in dimensionTotals){ var name=await c.ExecuteScalarAsync<string>("SELECT name FROM valora.form_dimensions WHERE id=@id",new{id=dt.Key},tx); await c.ExecuteAsync("INSERT INTO valora.dimension_scores(organization_id,response_id,dimension_name,score,max_score,percentage,level_label) VALUES (@organizationId,@responseId,@name,@score,25,@percentage,@label)",new{organizationId=(Guid)s.organization_id,responseId=id,name,score=dt.Value,percentage=Math.Round(dt.Value/25*100,2),label},tx); } var code=$"VAL-{id:N}"[..14]; await c.ExecuteAsync("INSERT INTO valora.certificates(organization_id,response_id,certificate_code,participant_name,issuer_name,survey_name,score_label,maturity_label) VALUES (@organizationId,@id,@code,@ParticipantName,'Valora Pulse™','Diagnóstico Valora Insight™',@scoreLabel,@label)",new{organizationId=(Guid)s.organization_id,id,code,r.ParticipantName,scoreLabel=$"{total}/125",label},tx); if(!string.IsNullOrWhiteSpace(r.ParticipantEmail)) { await c.ExecuteAsync("INSERT INTO communication.email_jobs(organization_id,response_id,recipient_email,subject,template_key,status,payload_json) VALUES (@organizationId,@id,@ParticipantEmail,'Valora Insight™ - Seu diagnóstico está pronto','result-ready','pending',jsonb_build_object('score',@total,'level',@label))",new{organizationId=(Guid)s.organization_id,id,r.ParticipantEmail,total,label},tx); await c.ExecuteAsync("INSERT INTO communication.communications(organization_id,survey_id,response_id,channel,event_type,status,recipient_masked) VALUES (@organizationId,@surveyId,@id,'email','result-ready','pending',@masked)",new{organizationId=(Guid)s.organization_id,surveyId,id,masked=r.ParticipantEmail},tx); } tx.Commit(); return id;} catch{tx.Rollback(); throw;} }
 public async Task<dynamic?> GetResultAsync(Guid responseId){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT r.id,r.participant_name,rs.total_score AS TotalScore,rs.percentage,rs.maturity_label AS Level,c.certificate_code AS ValidationCode FROM valora.responses r LEFT JOIN valora.result_scores rs ON rs.response_id=r.id LEFT JOIN valora.certificates c ON c.response_id=r.id WHERE r.id=@responseId",new{responseId});}
 public async Task<int> CountActiveSurveysAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valora.surveys WHERE organization_id=@organizationId AND status='active' AND is_deleted=false",new{organizationId});} public async Task<int> CountResponsesThisMonthAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valora.responses WHERE organization_id=@organizationId AND created_at >= date_trunc('month', now()) AND is_deleted=false",new{organizationId});}}
public sealed class AuditRepository(IDbConnectionFactory f):IAuditRepository{ public async Task AddAsync(AuditEntry e){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO audit.audit_logs(organization_id,user_id,action,entity_type,entity_id,message,metadata_json) VALUES (@OrganizationId,@UserId,@Action,@EntityType,@EntityId,@Message,CAST(@MetadataJson AS jsonb))",e);}}

public sealed class FormRepository(IDbConnectionFactory f):IFormRepository{ public async Task<dynamic?> GetAsync(Guid id){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT * FROM valora.forms WHERE id=@id AND is_deleted=false",new{id});}}
public sealed class ResultRepository(IDbConnectionFactory f):IResultRepository{ public async Task<dynamic?> GetByResponseAsync(Guid responseId){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT * FROM valora.result_scores WHERE response_id=@responseId",new{responseId});}}
public sealed class CertificateRepository(IDbConnectionFactory f):ICertificateRepository{ public async Task<dynamic?> GetByResponseAsync(Guid responseId){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT * FROM valora.certificates WHERE response_id=@responseId",new{responseId});} public async Task CreateMetadataAsync(Guid responseId,string validationCode,string status){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO valora.certificates(response_id,certificate_code,issuer_name) VALUES (@responseId,@validationCode,@status) ON CONFLICT (certificate_code) DO UPDATE SET updated_at=now()",new{responseId,validationCode,status});}}
public sealed class CommunicationRepository(IDbConnectionFactory f):ICommunicationRepository{ public async Task AddEmailJobAsync(Guid responseId,string toEmail,string status){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO communication.email_jobs(response_id,recipient_email,subject,template_key,status) VALUES (@responseId,@toEmail,'Valora Insight™ - Seu diagnóstico está pronto','result-ready',@status)",new{responseId,toEmail,status});} public async Task<IReadOnlyList<dynamic>> ListAsync(Guid? organizationId=null){using var c=f.Create(); var rows=await c.QueryAsync("SELECT * FROM communication.communications WHERE (@organizationId IS NULL OR organization_id=@organizationId) ORDER BY created_at DESC LIMIT 100",new{organizationId}); return rows.ToList();}}
public sealed class MigrationRepository(IDbConnectionFactory f):IMigrationRepository{ public async Task<dynamic?> GetStatusAsync(){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT (SELECT count(*) FROM migration.import_batches) AS import_batches,(SELECT count(*) FROM migration.compare_reports) AS compare_reports");} public async Task SaveCompareReportAsync(string reportJson){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO migration.compare_reports(report_json) VALUES (CAST(@reportJson AS jsonb))",new{reportJson});}}
